    async def broadcast_trade_update(self, trade: Trade):
        initiator = self.players.get(trade.initiator_id)
        recipient = self.players.get(trade.recipient_id)
        
        trade_data = json.dumps({
            'action': 'trade_updated',
            'trade': trade.to_dict()
        })
        
        if initiator and initiator.websocket:
            await initiator.websocket.send(trade_data)
            
        if recipient and recipient.websocket:
            await recipient.websocket.send(trade_data)
            
    async def start_server(self, host='localhost', port=8765):
        async with websockets.serve(self.handle_client, host, port):
            print(f"Game server started on ws://{host}:{port}")
            await asyncio.Future()

